import{St as e,j as t,k as n}from"./C2wy_3lr.js";import"./CT0T0Gak.js";import"./cry5Dbjr.js";var r={title:`SETU Highlights DREAMER at Panel Discussion with Ukrainian Ambassador`,date:`21.03.2026`,categories:[`events`],gallery:`SETU-discussion-ukrainian-ambassador`,published:!0},{title:i,date:a,categories:o,gallery:s,published:c}=r,l=t(`<p>South East Technological University (SETU) recently took part in an important panel discussion on “Ukraine and Ireland: Strengthening Connections through Culture, Diplomacy and Friendship”, hosted by the Ukrainian Student Society on the SETU Carlow campus.</p> <p>The event featured <strong>Ukrainian Ambassador to Ireland, Larysa Gerasko</strong>, who acknowledged the <strong>strong support</strong> that both Ireland and SETU continue to provide to Ukraine and to Ukrainian students studying across the university’s campuses in Carlow, Wexford, and Waterford. Currently, <strong>665 Ukrainian students</strong> are undertaking various courses at SETU. During the discussion, students also shared their <strong>positive experiences of academic and student life</strong> at the university.</p> <p>During the event, <strong>John Wall</strong> had the opportunity to introduce the Ambassador to SETU’s involvement in the <strong>DREAMER</strong> project — Development and Reconstruction Empowerment through Advanced Project Management Education and Research. Funded by the <strong>European Union through the Erasmus+ programme</strong>, <strong>DREAMER aims to support Ukraine’s rebuilding efforts</strong>, strengthen innovation in sustainable project management education, and promote international cooperation through shared learning and expertise.</p> <p>The conversation also highlighted the <strong>strong partnership</strong> between SETU and Ukrainian higher education institutions involved in DREAMER, including <strong>Kyiv National University of Construction and Architecture</strong> and <strong>Taras Shevchenko National University of Kyiv</strong>, the latter being <strong>Ambassador Gerasko’s alma mater</strong>.</p> <p>SETU’s contribution to DREAMER reflects its <strong>ongoing commitment to international academic cooperation and support for Ukraine</strong>. This commitment was further demonstrated in <strong>September 2025</strong>, when the Department of Architecture & Built Environment in Waterford hosted academic partners from Ukraine. The visit included <strong>working sessions focused on refining module templates and structures, project implementation, and peer review of syllabus assessments</strong> as part of the project’s ongoing activities. Beyond the formal agenda, these exchanges also helped to deepen academic ties and reinforce collaboration between SETU and its Ukrainian partners.</p> <p>Through initiatives such as <strong>DREAMER</strong>, SETU continues to play an active role in building meaningful connections between Ireland and Ukraine while contributing to <strong>capacity building for reconstruction, education, and long-term resilience</strong>.</p>`,1);function u(t){var r=l();e(10),n(t,r)}export{u as default,r as metadata};